import { createComponent } from '@animus-ui/system';
import 'virtual:animus/styles.css';
import { ds } from '../test-system';

export const LayoutContainer = createComponent('div', 'animus-LayoutContainer-abe306b3', {"states":["loading","sidebar"]});

export const ContentContainer = createComponent('div', 'animus-ContentContainer-e220dc36', {});

const SidebarContainer = createComponent('div', 'animus-SidebarContainer-f73647ad', {});

extract/layout.tsx.css:
@layer anm-global, anm-base, anm-variants, anm-compounds, anm-states, anm-system, anm-custom;

@layer anm-base {
  .animus-ContentContainer-e220dc36 {
    padding-left: 1.5rem;
    padding-right: 1.5rem;
    padding-top: 1.5rem;
    position: relative;
  }
  @media (min-width: 768px) {
    .animus-ContentContainer-e220dc36 {
      padding-left: 4rem;
      padding-right: 4rem;
      padding-top: 3rem;
    }
  }
  @media (min-width: 1440px) {
    .animus-ContentContainer-e220dc36 {
      padding-left: 6rem;
      padding-right: 6rem;
    }
  }
  .animus-LayoutContainer-abe306b3 {
    overflow: hidden;
    position: relative;
    z-index: 1;
    background-color: var(--color-background);
    --current-bg: var(--color-background);
    min-height: 100vh;
    width: 1;
    display: grid;
    color: var(--color-text);
    font-size: 1rem;
  }
  @media (min-width: 480px) {
    .animus-LayoutContainer-abe306b3 {
      font-size: 1.125rem;
    }
  }
  @media (min-width: 768px) {
    .animus-SidebarContainer-f73647ad {
      position: static;
    }
  }
}

@layer anm-variants {
  @layer standalone, composed;
  @layer composed {
  }
}

@layer anm-states {
  .animus-LayoutContainer-abe306b3--loading {
    opacity: 0;
  }
  .animus-LayoutContainer-abe306b3--sidebar {
    grid-template-areas: "header header" "content content";
  }
  @media (min-width: 768px) {
    .animus-LayoutContainer-abe306b3--sidebar {
      grid-template-areas: "header header" "sidebar content";
    }
  }
}

