import { createComponent } from '@animus-ui/system';
import 'virtual:animus/styles.css';
import { ds } from '../test-system';

// Component with 3 variant options — only "stroke" will be used in JSX
export const Button = createComponent('button', 'animus-Button-dc5e33a5', {"variants":{"variant":{"options":["fill","stroke","ghost"],"default":"fill"}},"states":["disabled","loading"]});

// Component that is NEVER rendered in JSX (dead component)
export const Spacer = createComponent('div', 'animus-Spacer-fa3a2979', {});

// JSX usage — only "stroke" variant used, only "disabled" state activated
// Button rendered WITHOUT variant prop → default "fill" implicitly used
export function App() {
  return (
    <div>
      <Button variant="stroke" disabled>
        Click
      </Button>
      <Button>Default</Button>
    </div>
  );
}

