import { createComponent } from '@animus-ui/system';
import { systemPropMap, systemPropGroups } from 'virtual:animus/system-props';
import 'virtual:animus/styles.css';
import { ds } from '../test-system';

// Variant with custom prop name + groups — reproduces StratumRow pattern
export const StratumRow = createComponent('div', 'animus-StratumRow-d568a7b0', {"variants":{"kind":{"options":["terminal"]}},"systemPropNames":[].concat(systemPropGroups.space)}, systemPropMap);

// Variant with default prop name + groups
export const SimpleVariantGroups = createComponent('div', 'animus-SimpleVariantGroups-b2c3ec4f', {"variants":{"variant":{"options":["filled","outlined"]}},"systemPropNames":[].concat(systemPropGroups.space)}, systemPropMap);

// Variant only (no groups) — control case
export const VariantOnly = createComponent('div', 'animus-VariantOnly-6283cd3f', {"variants":{"kind":{"options":["active"]}}});

// Groups only (no variant) — control case
export const GroupsOnly = createComponent('div', 'animus-GroupsOnly-41e6cc9e', {"systemPropNames":[].concat(systemPropGroups.space)}, systemPropMap);

// Variant with defaultVariant — reconciler tracks this for pruning
export const TrackedVariant = createComponent('div', 'animus-TrackedVariant-1b0917a3', {"variants":{"mode":{"options":["idle","active","disabled"],"default":"idle"}}});

