export const PatternC = createComponent('button', 'animus-PatternC-6fc6b524', {});

export const AppC = () => <PatternC />;

code.selector-rules-compound-alias.tsx:
import { createComponent } from '@animus-ui/system';
import 'virtual:animus/styles.css';
import { ds } from '../../setup';

// Pattern D — two _aliased keys including one with a compound selector alias
// (_selected → '&:[aria-selected="true"], &[data-selected]'), plus a token ref
// inside a shorthand value. Mirrors TabGroup.tsx's TabButton. Observed in build:
// total component drop (0 rules).
export const PatternD = createComponent('button', 'animus-PatternD-d307a952', {});

export const AppD = () => <PatternD />;

code.selector-rules-create-element.tsx:
import { createComponent } from '@animus-ui/system';
import 'virtual:animus/styles.css';
import { createElement } from 'react';

import { ds } from '../../setup';

// Pattern E — component rendered via React.createElement() with a bare
// identifier (not JSX, not member expression). Mirrors CloseButton's usage in
// Drawer.tsx where `createElement(CloseButton, { onClick: ... })` is the only
// reference. Observed in showcase dist: CloseButton dropped entirely.
//
// Hypothesis: JSX scanner recognizes <Component> and <Namespace.Member>
// usages, but does NOT recognize createElement(bareIdent, ...) as rendering.
// Reconciler then eliminates as "not rendered and not a parent."
export const PatternE = createComponent('button', 'animus-PatternE-061669d8', {});

export const AppE = () => createElement(PatternE, {});

code.selector-rules-full-chain.tsx:
import { createComponent } from '@animus-ui/system';
import 'virtual:animus/styles.css';
import { ds } from '../../setup';

// Pattern G — close mirror of CopyButton's authoring. Full chain:
// .styles({ ..., _hover: {...}, _focusVisible: {...token ref...} })
// .variant({...}).states({...}).asElement('button').
// Observed in showcase dist: base + _hover + variants + states all extract,
// but :focus-visible drops. This isolates the chain-richness interaction.
export const PatternG = createComponent('button', 'animus-PatternG-7a1c632e', {"variants":{"size":{"options":["small","medium"],"default":"small"}},"states":["pressed"]});

export const AppG = () => <PatternG size="small" pressed />;

code.selector-rules-prospective-unrendered.ts:
import { createComponent } from '@animus-ui/system';
import 'virtual:animus/styles.css';
import { ds } from '../../setup';

// Pattern H — ds-built component that is defined but never rendered.
// In production (dev_mode=false) the reconciler eliminates it as
// "component not rendered and not a parent".
// In dev mode (dev_mode=true) Position 3 dictates the component stays in
// the manifest (HMR ergonomics) but `report.eliminated_details` carries a
// prospective entry with kind="prospective_component" so the vite/next
// plugin can emit a warning at authoring time.
export const PatternH = createComponent('div', 'animus-PatternH-b4cb5db9', {});

